const ignoreFields = ['telefone', 'unidade', 'convenio', 'procedimento', 'data_agendamento', 'falar_com_humano', 'eh_indicacao_dentista']

// Para que esse código funcione corretamente, os nomes dos campos recebidos no workflow devem ser os MESMOS que as COLUNAS da tabela do lead
const clientePhone = $('inicio_fluxo').last().json.telefone;

function getFieldsToUpdate(currentData, databaseData) {
  const updates = {};

  if (databaseData.nome && databaseData.nome !== 'nao_informado') {
    return {};
  }

  for (const key in currentData) {
    if (ignoreFields.includes(key)) continue;

    const currentValue = currentData[key];
    const databaseValue = databaseData[key];

    if (currentValue === 'nao_informado' || currentValue === databaseValue || currentValue === null) continue;

    updates[key] = currentValue;
  }

  return updates;
}

function buildUpdateSQL(updates) {
  const setClauses = Object.entries(updates).map(
    ([key, value]) => {
      if (key != 'eh_dentista')
      {
        return `${key} = '${value.replace(/'/g, "''")}'`
      } else if (key == 'eh_dentista') 
      {
        return `is_dentista = ${value}`
      } else {
        return `${key} = ${value}`
      }
    }
  );
  if (setClauses.length === 0) return null;

  return `UPDATE public.cliente SET ${setClauses.join(', ')}, updated_at = now() WHERE telefone = '${clientePhone}';`;
}

const currentLeadData = $('inicio_fluxo').last().json;
const databaseLeadData = $('SELECT cliente').last().json;


const updatedLeadData = {...currentLeadData};

const updates = getFieldsToUpdate(updatedLeadData, databaseLeadData);
const sql = buildUpdateSQL(updates);

return {
  sql: sql,
  updated_fields: updates,
};

