const exams = $('GET exames').all().map(item => item.json);

const formattedList = exams.map(e => `${e.nome_normalizado}: ${e.id_procedimento}`).join("\n");

return [
  {
    json: {
      examList: formattedList
    }
  }
];

const data = $('inicio_fluxo').last().json;

function clean(val) {
  return val === 'nao_informado' ? null : val;
}

return [{
  json: {
    telefone: data.telefone,
    unidade_id: clean(data.unidade),
    data_agendamento: clean(data.data_agendamento),
    convenio: clean(data.convenio),
    dentista: clean(data.eh_indicacao_dentista),
    procedimento: clean(data.procedimento),
  }
}];

